import _ from 'lodash'
import { 
  SET_CURRENTDATA,
  DELETE_CURRENTDATA, 
} from './mutation-types';
import { State } from './state';

export default {
  [SET_CURRENTDATA](state: State, payload: any) {
    state.currentData = payload;
  },
  [DELETE_CURRENTDATA](state: State, payload: any) {
    const { currentData } = state
    const index = _.findIndex(currentData[payload.id], { name: payload.name })
    currentData[payload.id].splice(index, 1)
    state.currentData = currentData;
  },
};
/* eslint-disable */
